// I wrapped every single function including tiny helpers:
function add(a: number, b: number): Result<number, MathError> {
  return Result.try({
    try: () => a + b,
    catch: (e) => new MathError({ cause: e }),
  });
}

// My domain error:
class UserNotFound extends Error {
  constructor(id: string) {
    super(`User ${id} not found`);
  }
}

// My service:
async function getUser(id: string): Promise<Result<User, UserNotFound>> {
  return Result.tryPromise({
    try: async () => {
      const user = await db.query('SELECT * FROM users WHERE id = $1', [id]);
      if (!user) throw new UserNotFound(id);
      return user;
    },
    catch: (e) => {
      if (e instanceof UserNotFound) return e;
      // Catch the panic too, just in case
      return new UserNotFound('unknown');
    },
  });
}

// My controller calls getUser but still uses try/catch:
async function handleGetUser(req, res) {
  try {
    const result = await getUser(req.params.id);
    if (result.ok) {
      res.json(result.value);
    } else {
      res.status(404).json({ error: result.error.message });
    }
  } catch (e) {
    res.status(500).json({ error: 'Internal error' });
  }
}
